const STORY_IMAGE_ASSET_BY_ID = new Map<string, StoryImageAsset>()
for (const asset of STORY_IMAGE_ASSETS) {
  STORY_IMAGE_ASSET_BY_ID.set(asset.id, asset)
  for (const alias of asset.aliases || []) {
    STORY_IMAGE_ASSET_BY_ID.set(alias, asset)
  }
}

export const STORY_MOMENT_ASSET_BY_ID = new Map<string, StoryMomentAsset>(
  STORY_MOMENT_ASSETS.map(asset => [asset.id, asset] as const),
)

export function getStoryImageAsset(idOrTitle: string): StoryImageAsset | null {
  const key = idOrTitle.trim()
  if (!key) return null
  const direct = STORY_IMAGE_ASSET_BY_ID.get(key)
  if (direct) return direct
  // Strict matching: only exact matches to prevent false positives
  // (e.g. "公园" should NOT match "雨夜公园长椅远景")
  return STORY_IMAGE_ASSETS.find(asset =>
    key === asset.title ||
    (asset.aliases || []).some(alias => key === alias)
  ) || null
}

export function getStoryMomentAsset(id: string): StoryMomentAsset | null {
  return STORY_MOMENT_ASSET_BY_ID.get(id.trim()) || null
}

